INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000000', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'text', '{"html":"<h3>From Coordinates to Area</h3><p>Once a closed traverse has been adjusted and every corner has a balanced <strong>(X, Y)</strong> coordinate (easting, northing), the enclosed <strong>area</strong> follows from pure geometry &mdash; no further field work is needed. This is the most common way a surveyor computes the area of a parcel today, because total stations and COGO software deliver coordinates directly. The two classical techniques, the <strong>coordinate (shoelace) method</strong> and the <strong>Double Meridian Distance (DMD) method</strong>, are algebraically identical; they differ only in how the arithmetic is organized for hand computation.</p><p>The area you compute is the <em>mathematically closed</em> area of the figure defined by the coordinates. Before computing area, the traverse must close: latitudes and departures should sum to (near) zero and the linear misclosure must be balanced. Computing area on an unadjusted traverse bakes the closure error into the parcel size, so adjust first, then compute area.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000001', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'text', '{"html":"<h3>The Coordinate (Shoelace) Method</h3><p>Number the corners <strong>1, 2, 3, &hellip;, n</strong> consecutively around the boundary and return to corner 1. The signed double area is the sum of cross-products of successive coordinates; taking the absolute value and halving gives the area. The name &lsquo;shoelace&rsquo; comes from the criss-cross pattern of multiplying x of one point by y of the next. Two equivalent forms are common: the &lsquo;successive&rsquo; form 2A = Σ(x_i&middot;y_{i+1} &minus; x_{i+1}&middot;y_i), and the &lsquo;cross&rsquo; form 2A = Σ x_i(y_{i+1} &minus; y_{i&minus;1}). Both require that the list of points be ordered consistently (all clockwise or all counter-clockwise) and that the polygon close back on point 1.</p><p>The sign of the unhalved sum tells you the direction of travel: positive for one orientation, negative for the other. Because physical area is never negative, take the absolute value. A non-zero but tiny residual when you expect zero usually signals a keying error in a coordinate.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000002', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'equation', '{"latex":"A = \\frac{1}{2}\\left|\\sum_{i=1}^{n} \\left(x_i\\,y_{i+1} - x_{i+1}\\,y_i\\right)\\right|","label":"Area by coordinates (shoelace), with point n+1 = point 1","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000003', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'text', '{"html":"<h3>The Double Meridian Distance (DMD) Method</h3><p>Before calculators, surveyors organized the same computation as a tabular routine using <strong>latitudes</strong> (north&ndash;south components) and <strong>departures</strong> (east&ndash;west components) of each course. The <strong>Meridian Distance</strong> of a course is the perpendicular distance from a reference meridian to the midpoint of that course; doubling it avoids fractions, giving the <strong>Double Meridian Distance (DMD)</strong>. The DMDs are built up course by course with a simple recurrence, and the double area is the sum of each DMD times that course''s latitude.</p><p>The bookkeeping rules are: (1) the DMD of the <em>first</em> course equals its own departure; (2) the DMD of each <em>following</em> course equals the previous DMD plus the previous course''s departure plus the current course''s departure; and (3) the DMD of the <em>last</em> course equals its own departure (a built-in arithmetic check). Multiply each DMD by its latitude, sum, take the absolute value, and halve to get the area. Because both methods integrate the same closed figure, the answer is identical to the shoelace result.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000004', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'equation', '{"latex":"2A = \\sum_{i=1}^{n} \\big(\\text{DMD}_i \\times \\text{Lat}_i\\big), \\qquad \\text{DMD}_i = \\text{DMD}_{i-1} + \\text{Dep}_{i-1} + \\text{Dep}_i","label":"Double area by DMD","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000005', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'table', '{"headers":["Course","DMD rule","Double-area term"],"rows":[["First","DMD = its own departure","DMD × Lat"],["Intermediate","DMD = prev DMD + prev Dep + this Dep","DMD × Lat"],["Last","DMD = its own departure (check)","DMD × Lat"],["Total","—","Σ(DMD × Lat) = 2A"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000006', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'text', '{"html":"<h3>Reporting the Area</h3><p>Surveying areas are reported in <strong>square feet</strong> and, for parcels, in <strong>acres</strong> (1 acre = 43,560 sq ft). In Texas, historic Spanish/Mexican grants are sometimes still measured in <strong>varas</strong> and <strong>labors/leagues</strong>, but modern field work converts to feet (U.S. survey foot for State Plane work) and acres for the deed. Carry full precision through the computation and round only the final answer. A common professional convention is to report parcel area to the nearest 0.001 acre (or to a hundredth of an acre on rural tracts), never to more figures than the coordinates justify.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000007', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'callout', '{"type":"warning","text":"Texas differs: Texas areas in older deeds may be stated in varas, labors (177.1 acres), and leagues (4,428.4 acres) from the Spanish/Mexican and Republic survey system, because Texas never used the federal PLSS section/acre grid. When retracing such a grant, confirm whether the vara in use was the Texas vara of 33⅓ inches before converting to acres."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000008', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A closed quadrilateral with corner (X, Y) coordinates. The shoelace method cross-multiplies successive coordinates to yield twice the enclosed area."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0001-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'key_takeaways', '{"title":"Key Takeaways","items":["Adjust (balance) the traverse before computing area so closure error is not absorbed into the parcel size.","The shoelace formula A = ½|Σ(x_i·y_{i+1} − x_{i+1}·y_i)| computes area directly from ordered corner coordinates.","DMD is the tabular hand-method equivalent: DMD of course 1 = its departure; each later DMD adds the two adjacent departures; 2A = Σ(DMD × Lat).","Take the absolute value, halve the double area, and convert square feet to acres by dividing by 43,560.","In Texas, watch for legacy vara/labor/league units in old grants and confirm the vara length before converting."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000000', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'text', '{"html":"<h3>Triangles: The Building Block of Area</h3><p>The triangle is the fundamental unit of area computation because any straight-sided figure can be divided into triangles. Two field-friendly formulas dominate. When you measure <strong>two sides and the included angle</strong>, the area is one-half the product of the two sides times the sine of the angle between them: <strong>A = ½&middot;a&middot;b&middot;sin C</strong>. When you instead know <strong>all three side lengths</strong> &mdash; common when only distances were taped &mdash; use <strong>Heron''s formula</strong>, which needs no angle at all. Both are exact; the choice depends on what was measured in the field.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000001', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'equation', '{"latex":"A = \\tfrac{1}{2}\\,a\\,b\\,\\sin C \\qquad\\text{(two sides + included angle)}","label":"Triangle area, side-angle-side","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000002', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'equation', '{"latex":"A = \\sqrt{s(s-a)(s-b)(s-c)}, \\qquad s = \\frac{a+b+c}{2}","label":"Heron''s formula (three sides)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000003', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'text', '{"html":"<h3>Triangulating a Polygon</h3><p>To find the area of an irregular but straight-sided tract by triangulation, pick a vertex (or an interior point) and draw diagonals to every other corner, slicing the polygon into a fan of triangles. Compute each triangle''s area with side-angle-side or Heron''s formula, then <strong>sum them</strong>. The method is the classical &lsquo;chain-and-tape&rsquo; approach: a survey crew with only a tape can establish triangles by measuring all three sides of each, and total the parcel without ever turning an angle. Triangulation is also how area is checked independently of the coordinate method &mdash; if the triangulated total and the shoelace total disagree by more than rounding, look for a blunder.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000004', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'text', '{"html":"<h3>Irregular Boundaries: Offsets to a Curved Line</h3><p>Natural boundaries &mdash; a creek bank, a tree line, the edge of a road &mdash; rarely follow straight courses. The standard technique is to run a straight <strong>reference (base) line</strong> near the boundary and measure perpendicular <strong>offsets</strong> from the line out to the boundary at regular intervals. The strip of land between the straight line and the wandering boundary is then computed from those offsets. Two numerical-integration rules do this:</p><ul><li>The <strong>trapezoidal rule</strong> treats each pair of adjacent offsets as the parallel sides of a trapezoid. It works for any number of equal intervals and is simple, but it slightly under- or over-estimates a curve because it connects offset tips with straight chords.</li><li><strong>Simpson''s one-third rule</strong> fits a parabola through each set of three successive offsets, capturing curvature. It is more accurate but <em>requires an even number of equal intervals</em> (an odd number of offsets).</li></ul>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000005', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'equation', '{"latex":"A \\approx d\\left[\\frac{h_0 + h_n}{2} + (h_1 + h_2 + \\cdots + h_{n-1})\\right]","label":"Trapezoidal rule (common interval d, offsets h)","display":"block"}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000006', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'equation', '{"latex":"A \\approx \\frac{d}{3}\\Big[h_0 + h_n + 4(h_1+h_3+\\cdots) + 2(h_2+h_4+\\cdots)\\Big]","label":"Simpson''s one-third rule (even number of equal intervals)","display":"block"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000007', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'table', '{"headers":["Method","Boundary model","Interval requirement","Relative accuracy"],"rows":[["Trapezoidal rule","Straight chords between offset tips","Any number of equal intervals","Good; biased on strong curves"],["Simpson''s 1/3 rule","Parabolic arcs through offset triples","Even number of equal intervals (odd # offsets)","Better on smooth curves"],["Triangulation","Straight-sided figure","None (uses measured triangles)","Exact for straight boundaries"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000008', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'callout', '{"type":"info","text":"Memory aid for Simpson''s rule weighting: the two END offsets get weight 1, the ODD-position interior offsets get weight 4, and the EVEN-position interior offsets get weight 2 — then multiply the whole bracket by d/3."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Equally spaced offsets h0…hn from a straight base line to an irregular boundary, used by the trapezoidal and Simpson''s rules."}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0002-0000-0000-000000000010', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'key_takeaways', '{"title":"Key Takeaways","items":["Triangle area is ½·a·b·sin C (two sides + included angle) or Heron''s formula (three sides).","Any straight-sided polygon can be split into triangles and totaled; this checks the coordinate method.","Irregular curved boundaries are measured by equally spaced perpendicular offsets from a base line.","The trapezoidal rule (any number of intervals) averages adjacent offsets; Simpson''s 1/3 rule (even # of intervals) fits parabolas and is more accurate.","Simpson''s weighting: ends ×1, odd interior offsets ×4, even interior offsets ×2, all times d/3."]}'::jsonb, 10);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000000', '704310c8-fb7a-49e1-8912-62f081890afa', 'text', '{"html":"<h3>The Division-of-Land Problem</h3><p><strong>Partitioning</strong> is the inverse of the area problem: instead of being handed the corners and asked for the area, the surveyor is handed a <em>required area</em> and asked to locate a <strong>dividing line</strong> that cuts it off. The need arises constantly &mdash; splitting an estate among heirs, carving a building lot from a farm, or conveying &lsquo;the south 10 acres.&rsquo; The work blends coordinate geometry with a clear understanding of the client''s intent: which part is to be the specified size, and what physical or legal feature the new line must respect.</p><p>The general strategy is to write the area of the cut-off portion as a function of the unknown that fixes the line (a distance along a side, an offset, or a coordinate), set that area equal to the target, and solve. Because area is often quadratic in the unknown, expect to solve a linear or quadratic equation, then convert the solution back into a staking distance or bearing.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000001', '704310c8-fb7a-49e1-8912-62f081890afa', 'text', '{"html":"<h3>Case 1 — A Line Parallel to a Given Side</h3><p>A frequent request is to cut off a required area with a line <strong>parallel to an existing boundary</strong> (for example, splitting a rectangular field into a road frontage strip and a back lot). If the parcel is a simple trapezoid or rectangle, the cut-off strip is itself a rectangle or trapezoid, and its area is a straightforward function of the perpendicular distance between the side and the new line. Setting strip-area = target area and solving gives the offset at which to set the parallel line. For a true rectangle, the offset is simply the target area divided by the width of the parcel.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000002', '704310c8-fb7a-49e1-8912-62f081890afa', 'equation', '{"latex":"d = \\frac{A_{\\text{target}}}{w}\\quad\\text{(parallel cut on a rectangle of width } w)","label":"Offset of a parallel dividing line on a rectangular parcel","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000003', '704310c8-fb7a-49e1-8912-62f081890afa', 'text', '{"html":"<h3>Case 2 — A Line Through a Fixed Point</h3><p>Sometimes the dividing line must pass through a <strong>specified point</strong> &mdash; an existing corner, a gate, a well, or a monument the parties agree on &mdash; and still cut off the required area. Here the line is pinned at one end, and the unknown is where it strikes the opposite boundary. You express the area of the triangle or quadrilateral formed between the fixed point, the swing point on the far side, and the intervening corners; set it equal to the target; and solve for the swing-point location. The result is then converted to a bearing and distance from the fixed point so the line can be staked.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000004', '704310c8-fb7a-49e1-8912-62f081890afa', 'text', '{"html":"<h3>Case 3 — Cutting Off a Required Acreage</h3><p>The most general case asks simply to sever a stated acreage (&lsquo;convey 5.00 acres out of the northeast corner&rsquo;) with the new line meeting two specified boundaries. The surveyor computes coordinates of the parcel, chooses the two sides the cut line will intersect, and writes the cut-off area (usually by the coordinate method) in terms of the two unknown intersection distances tied by the line''s geometry. Solving yields the exact corner positions of the new tract. Throughout, the surveyor must produce a <strong>closed, mathematically exact</strong> new boundary and a metes-and-bounds description for each resulting parcel.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000005', '704310c8-fb7a-49e1-8912-62f081890afa', 'table', '{"headers":["Division case","Fixed condition","Solve for"],"rows":[["Parallel to a side","Direction (parallel) of cut line","Perpendicular offset of the line"],["Through a fixed point","One endpoint pinned at a point","Where the line strikes the far boundary"],["Cut off acreage","Target area + two boundaries to meet","Both new corner positions"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000006', '704310c8-fb7a-49e1-8912-62f081890afa', 'callout', '{"type":"warning","text":"Texas differs: Dividing a tract into two or more parts for sale usually constitutes a ''subdivision'' under Texas Local Government Code Ch. 212 (municipal) or Ch. 232 (county), triggering platting and plat-approval requirements. A surveyor cannot lawfully carve out lots that evade these rules, and many counties bar conveyances that create new landlocked parcels without access. Confirm the platting and access requirements before staking a division line."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000007', '704310c8-fb7a-49e1-8912-62f081890afa', 'accordion', '{"sections":[{"title":"Worked idea: cut 5 acres off a rectangular field","content":"<p>A rectangular field is 660 ft wide (east&ndash;west) and 990 ft deep (north&ndash;south), totaling 653,400 sq ft = 15.00 ac. To convey exactly 5.00 acres (217,800 sq ft) as a strip across the full 660-ft width with a line parallel to the north line, the strip depth is d = 217,800 &divide; 660 = <strong>330 ft</strong>. Set the dividing line 330 ft south of (and parallel to) the north boundary. The remaining tract is 660 &times; 660 = 435,600 sq ft = 10.00 ac, which checks against 15.00 &minus; 5.00.</p>","open":false}]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0003-0000-0000-000000000008', '704310c8-fb7a-49e1-8912-62f081890afa', 'key_takeaways', '{"title":"Key Takeaways","items":["Partitioning is the inverse area problem: locate a line that cuts off an exact target area.","Write the cut-off area as a function of the unknown, set it equal to the target, and solve (often a linear or quadratic).","Three standard cases: line parallel to a side, line through a fixed point, and cutting off a stated acreage.","Each resulting parcel must be a closed figure with its own exact metes-and-bounds description.","In Texas, divisions for sale typically trigger Ch. 212/232 platting rules and must not create landlocked tracts."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000000', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'text', '{"html":"<h3>Volumes for Earthwork</h3><p>Roads, channels, pads, and embankments require moving earth, and the quantity of earth governs the cost. The classic method is to cut <strong>cross-sections</strong> perpendicular to the centerline at regular <strong>stations</strong> (commonly every 50 or 100 ft), compute the <strong>area</strong> of cut or fill in each section, and then turn those end areas into a <strong>volume</strong> of the solid between successive sections. Each cross-section shows the existing ground profile and the proposed design (subgrade) profile; the area between them, above the design line, is <strong>cut</strong> (excavation) and the area below is <strong>fill</strong> (embankment).</p><p>Cut and fill must be tracked <strong>separately</strong>. They cannot simply be netted because earth changes volume when handled: excavated material <strong>swells</strong> when loosened and compacted fill <strong>shrinks</strong> relative to its in-place borrow volume. A mass-haul/earthwork analysis applies shrinkage and swell factors before balancing cut against fill.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000001', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'text', '{"html":"<h3>The Average-End-Area Method</h3><p>The workhorse formula treats the solid between two adjacent cross-sections as a prism whose cross-section is the <em>average</em> of the two end areas. If the two end areas are A1 and A2 and the stations are a distance L apart, the volume is the average area times the length. This <strong>average-end-area</strong> method is simple, conservative, and the standard for most highway and site earthwork. It is exact when the cross-section changes <em>linearly</em> between stations and slightly overestimates volume when the section is curved (concave) between stations &mdash; the basis of the prismoidal correction below.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000002', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'equation', '{"latex":"V = L\\cdot\\frac{A_1 + A_2}{2}","label":"Average-end-area volume (L between sections, end areas A1, A2)","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000003', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'text', '{"html":"<h3>The Prismoidal Formula</h3><p>A more accurate model treats the solid as a true <strong>prismoid</strong> &mdash; a solid with parallel end faces and plane sides &mdash; and uses three areas: the two ends plus the <strong>middle area A_m</strong> taken at the half-station. Note that A_m is the area of the section whose <em>dimensions</em> are the averages of the two ends; it is <strong>not</strong> the average of the two end areas. The prismoidal formula is exact for any prismoid (including pyramids, wedges, and the transition shapes typical of road grading) and is required where high accuracy matters or where a section changes shape strongly between stations.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000004', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'equation', '{"latex":"V = \\frac{L}{6}\\left(A_1 + 4A_m + A_2\\right)","label":"Prismoidal formula (A_m = area at the mid-section)","display":"block"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000005', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'callout', '{"type":"info","text":"Average-end-area is quick and slightly overestimates volume on curved transitions. The ''prismoidal correction'' is the difference (average-end-area volume − prismoidal volume); subtract it when contract specifications require prismoidal accuracy. For routine site grading, average-end-area is usually accepted."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000006', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'text', '{"html":"<h3>Cubic Yards and Earthwork Bookkeeping</h3><p>Earthwork in U.S. practice is paid for in <strong>cubic yards (CY)</strong>. Because 1 cubic yard = 27 cubic feet, divide any cubic-foot volume by 27 to report cubic yards. A typical computation runs the average-end-area (or prismoidal) volume in cubic feet between each pair of stations, sums across the project, and converts to cubic yards. The cut total and fill total are reported separately and then reconciled with shrinkage (fill) and swell (haul) factors to decide how much material must be imported (borrow) or hauled off (waste). This station-by-station tabulation feeds the mass-haul diagram used to plan the most economical movement of earth.</p>"}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000007', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'table', '{"headers":["Quantity","Conversion / relation"],"rows":[["Cubic feet → cubic yards","÷ 27"],["Average-end-area volume","L × (A1 + A2) / 2"],["Prismoidal volume","L × (A1 + 4·Am + A2) / 6"],["Cut vs. fill","Tracked separately (swell on cut, shrinkage on fill)"]]}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000008', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Adjacent cross-sections (end areas A1, A2) separated by station distance L. The average-end-area method models the earth between them as a prism of the mean cross-section."}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0004-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'key_takeaways', '{"title":"Key Takeaways","items":["Cross-sections at regular stations give cut/fill end areas; volume is computed between successive sections.","Average-end-area volume V = L·(A1 + A2)/2 is the standard method and is exact for linear change.","The prismoidal formula V = L·(A1 + 4·Am + A2)/6 uses a mid-section area and is exact for a prismoid (Am is NOT the average of the end areas).","Convert cubic feet to cubic yards by dividing by 27; report cut and fill separately.","Apply shrinkage/swell factors before balancing cut against fill in an earthwork (mass-haul) analysis."]}'::jsonb, 9);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000000', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'text', '{"html":"<h3>Volumes from a Contour Map</h3><p>When a site is large and irregular &mdash; a reservoir, a pond, a borrow pit, or a stockpile &mdash; cutting individual cross-sections is awkward, but a <strong>contour map</strong> of the surface is readily available from a topographic survey or aerial/LiDAR mapping. The <strong>contour-area (or contour-volume) method</strong> uses the horizontal area enclosed by each contour line and integrates those areas vertically. Here the <strong>contour interval</strong> (the vertical spacing between contours, e.g., 1 ft, 2 ft, or 5 ft) plays the role that station distance plays in the cross-section method.</p><p>The procedure: determine the area enclosed by each contour (by planimeter, by digitizing, or from the coordinate method applied to the contour''s outline), then treat successive contour areas as &lsquo;end areas&rsquo; separated by the contour interval and apply the average-end-area or prismoidal formula. Summing from the lowest contour up gives the cumulative volume &mdash; for a reservoir, the storage capacity at each pool elevation.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000001', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'equation', '{"latex":"V = \\frac{h}{2}\\big(A_0 + 2A_1 + 2A_2 + \\cdots + 2A_{n-1} + A_n\\big)","label":"Cumulative volume by contour areas (h = contour interval), average-end-area form","display":"block"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000002', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'text', '{"html":"<h3>Average-End-Area Between Contours</h3><p>For just two adjacent contours whose enclosed areas are A_lower and A_upper, separated vertically by the contour interval h, the volume of the layer between them is the familiar average of the two areas times the interval: <strong>V = h&middot;(A_lower + A_upper)/2</strong>. Working contour by contour and adding the layers yields the total volume. The expanded summation above is just the average-end-area rule applied across a whole stack of contours, where the interior areas each appear twice (once as the top of one layer and once as the bottom of the next).</p>"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000003', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'equation', '{"latex":"V_{\\text{layer}} = h\\cdot\\frac{A_{\\text{lower}} + A_{\\text{upper}}}{2}","label":"Volume of one layer between two contours","display":"block"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000004', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'text', '{"html":"<h3>Prismoidal Refinement and the Top &lsquo;Cap&rsquo;</h3><p>Where greater accuracy is required, apply the <strong>prismoidal formula</strong> across three successive contours, taking the middle contour as the mid-area A_m: V = (2h/6)(A0 + 4A1 + A2) for a pair of intervals. Two practical refinements matter. First, the highest material does not end on a contour but tapers to a <strong>peak</strong> (a stockpile apex) or the water surface; that top slice is computed as a cone or pyramid &mdash; one-third of the base area times its height. Second, if the very lowest area is essentially a point or a small flat, handle it likewise. Choosing a smaller contour interval improves accuracy at the cost of more area measurements.</p>"}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000005', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'table', '{"headers":["Element","Treatment"],"rows":[["Layer between two contours","h × (A_lower + A_upper) / 2"],["Three contours, higher accuracy","Prismoidal: (2h/6)(A0 + 4·A1 + A2)"],["Top above the highest contour (peak)","Cone/pyramid: ⅓ × A_top × height to apex"],["Total volume","Sum of all layers + top cap"]]}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000006', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'callout', '{"type":"info","text":"The contour-area method is the standard way to build a reservoir stage–storage (elevation–capacity) curve: cumulative volume below each contour elevation gives the storage available at that pool level. Modern practice computes the same result from a TIN or DEM surface model, but the underlying math is identical."}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000007', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: Nested contour areas A0…An separated by the contour interval h. Volume is integrated vertically by treating contour areas as successive end areas."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0005-0000-0000-000000000008', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'key_takeaways', '{"title":"Key Takeaways","items":["The contour-area method integrates the horizontal area enclosed by each contour, using the contour interval as the vertical ''length.''","Volume of one layer between contours = h·(A_lower + A_upper)/2; sum the layers for total volume.","The prismoidal formula across three contours improves accuracy; the top cap above the highest contour is a cone/pyramid (⅓·A·height).","Contour methods suit reservoirs, ponds, borrow pits, and stockpiles, and build elevation–capacity curves.","Smaller contour intervals increase accuracy at the cost of measuring more contour areas."]}'::jsonb, 8);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000000', 'df466917-ac9e-4799-a168-8475631ca487', 'text', '{"html":"<h3>Putting It Together: An Earthwork Run</h3><p>A complete earthwork computation chains together everything in this module. Starting from cross-sections (or a contour/surface model), you compute the <strong>end area</strong> of cut and fill at each station, apply the <strong>average-end-area</strong> (or prismoidal) formula between successive stations to get the volume of each segment, and then <strong>accumulate</strong> cut and fill down the alignment. The output is a station-by-station table feeding two running totals &mdash; total excavation (cut) and total embankment (fill) &mdash; expressed in cubic yards for payment.</p><p>This lesson is exercise-driven: the goal is fluency in the tabulation, the unit conversions, and the checks. A disciplined table with clear columns (station, cut area, fill area, segment length, cut volume, fill volume, cumulative cut, cumulative fill) prevents the most common blunders &mdash; misplaced decimals, mixing square feet with square yards, and netting cut against fill prematurely.</p>"}'::jsonb, 0);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000001', 'df466917-ac9e-4799-a168-8475631ca487', 'text', '{"html":"<h3>Shrinkage, Swell, and Borrow/Waste</h3><p>In-place soil does not keep its volume through the haul cycle. <strong>Swell</strong> describes how excavated material occupies more space when loosened (relevant to hauling), while <strong>shrinkage</strong> describes how material compacted into fill occupies <em>less</em> volume than it did in its borrow location (relevant to how much you must excavate to build a given embankment). A typical shrinkage factor might require, say, 1.10&ndash;1.25 in-place cubic yards of borrow to produce one compacted cubic yard of fill. After applying these factors, the engineer compares adjusted cut to adjusted fill: a surplus of cut becomes <strong>waste</strong> hauled off site; a deficit requires imported <strong>borrow</strong>.</p>"}'::jsonb, 1);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000002', 'df466917-ac9e-4799-a168-8475631ca487', 'equation', '{"latex":"V_{\\text{borrow}} = \\frac{V_{\\text{compacted fill}}}{1 - \\text{shrinkage}}","label":"In-place borrow needed to produce a compacted fill volume","display":"block"}'::jsonb, 2);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000003', 'df466917-ac9e-4799-a168-8475631ca487', 'text', '{"html":"<h3>The Balance Point and Mass-Haul Idea</h3><p>Earth is expensive to move, so designers try to <strong>balance</strong> cut and fill &mdash; using material excavated in cut sections to build nearby fill sections rather than importing or wasting. A <strong>balance point</strong> along the alignment is a station where cumulative cut equals cumulative fill, so material to that point is self-supplied. Plotting cumulative net volume against station produces the <strong>mass-haul diagram</strong>, whose shape reveals haul distances and directions and the most economical earth movement. While the full mass-haul analysis belongs to route design, the surveyor supplies its raw material: accurate end areas and volumes.</p>"}'::jsonb, 3);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000004', 'df466917-ac9e-4799-a168-8475631ca487', 'table', '{"headers":["Station","Cut area (sf)","Fill area (sf)","Seg. length (ft)","Cut vol (cy)","Fill vol (cy)"],"rows":[["10+00","120","0","—","—","—"],["11+00","80","0","100","370","0"],["12+00","20","40","100","185","74"],["13+00","0","150","100","37","352"]]}'::jsonb, 4);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000005', 'df466917-ac9e-4799-a168-8475631ca487', 'callout', '{"type":"info","text":"Unit-discipline check: end areas are usually in square FEET and stations in FEET, so a segment volume comes out in cubic FEET — divide by 27 to get cubic yards. A frequent blunder is forgetting the ÷27 or mixing square yards into a square-foot table. Compute volumes in consistent units first, convert last."}'::jsonb, 5);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000006', 'df466917-ac9e-4799-a168-8475631ca487', 'accordion', '{"sections":[{"title":"Worked check: one segment, average-end-area to cubic yards","content":"<p>Between two stations 100 ft apart, the cut end areas are A1 = 120 sf and A2 = 80 sf. Average-end-area volume = L&middot;(A1+A2)/2 = 100 &times; (120+80)/2 = 100 &times; 100 = 10,000 cubic feet. Convert: 10,000 &divide; 27 = <strong>370.4 cubic yards</strong> of cut for that segment. Repeat for every segment and sum the cut column; do the same for fill; never net them until shrinkage/swell are applied.</p>","open":false}]}'::jsonb, 6);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000007', 'df466917-ac9e-4799-a168-8475631ca487', 'callout', '{"type":"info","text":"📷 Figure (to be added): Figure: A mass-haul diagram. Stations where the cumulative-volume curve returns to the baseline are balance points (cut = fill)."}'::jsonb, 7);
INSERT INTO lesson_blocks (id, lesson_id, block_type, content, order_index) VALUES ('eeee0910-0006-0000-0000-000000000008', 'df466917-ac9e-4799-a168-8475631ca487', 'key_takeaways', '{"title":"Key Takeaways","items":["Build a station-by-station table: end areas → segment volumes (average-end-area or prismoidal) → cumulative cut and fill.","Compute volumes in consistent units (cubic feet) and convert to cubic yards last (÷27).","Apply swell to excavated/hauled material and shrinkage to compacted fill before comparing cut and fill.","A balance point is a station where cumulative cut equals cumulative fill; the mass-haul diagram guides economical earth movement.","Keep cut and fill separate until factored; report results with units and justified significant figures."]}'::jsonb, 8);
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000001', 'Coordinate (shoelace) method', 'A formula that computes the area of a closed polygon directly from its ordered corner coordinates: A = ½|Σ(x_i·y_{i+1} − x_{i+1}·y_i)|. The points must be listed consistently around the boundary and closed back on the first point.', NULL, 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000002', 'Double Meridian Distance (DMD)', 'Twice the perpendicular distance from a reference meridian to the midpoint of a traverse course. Double area = Σ(DMD × latitude). DMD of the first course equals its departure; each later DMD = previous DMD + previous departure + current departure.', 'A hand-computation route to the same area as the shoelace method.', 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000003', 'Acre conversion', '1 acre = 43,560 square feet. Divide a computed area in square feet by 43,560 to obtain acres.', NULL, 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000004', 'Heron''s formula', 'A way to compute a triangle''s area from its three side lengths a, b, c: A = √[s(s−a)(s−b)(s−c)], where s = (a+b+c)/2 is the semiperimeter. No angle measurement is required.', NULL, 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000005', 'Trapezoidal rule (offsets)', 'An area-by-offsets rule for an irregular boundary: A = d[(h0+hn)/2 + (h1+…+h_{n-1})], where d is the common offset interval and h are the perpendicular offsets. Works for any number of equal intervals.', NULL, 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000006', 'Simpson''s one-third rule', 'An offset rule that fits parabolas through offset triples: A = (d/3)[h0 + hn + 4(odd offsets) + 2(even offsets)]. Requires an even number of equal intervals and is more accurate than the trapezoidal rule for smooth curves.', NULL, 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000007', 'Offset', 'A perpendicular distance measured from a straight reference (base) line out to an irregular boundary at a regular interval. A series of offsets lets you compute the area of the strip between the line and the boundary.', NULL, 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000008', 'Land partition (division)', 'The inverse of an area computation: given a required area, locate the dividing line that cuts that exact area out of a parcel. Each new piece must close mathematically and get its own legal description.', NULL, 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000009', 'Parallel dividing line', 'A cut line run parallel to an existing boundary to sever a required area. On a rectangular parcel of width w, the line is set at offset d = A_target / w from that boundary.', NULL, 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000010', 'Subdivision (Texas Ch. 212/232)', 'Dividing a tract for sale into lots, which under Texas Local Government Code Ch. 212 (cities) or Ch. 232 (counties) triggers platting and plat-approval requirements that constrain how a surveyor may lay out division lines.', NULL, 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000011', 'Average-end-area method', 'A volume method that models the earth between two cross-sections as a prism of the mean cross-section: V = L·(A1 + A2)/2, where L is the distance between sections and A1, A2 are the end areas. Slightly overestimates volume on curved transitions.', NULL, 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000012', 'Prismoidal formula', 'An exact volume formula for a prismoid: V = (L/6)(A1 + 4·Am + A2), where Am is the area of the mid-section (a section whose dimensions are the averages of the two ends — not the average of the two areas).', NULL, 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000013', 'Cubic yard conversion', '1 cubic yard = 27 cubic feet. Divide a volume in cubic feet by 27 to report earthwork in cubic yards, the standard pay unit in U.S. construction.', NULL, 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000014', 'Shrinkage and swell', 'Earth changes volume when handled: excavated material swells (occupies more space loose), and placed fill shrinks (compacts to less than its borrow volume). Cut and fill are tracked separately and reconciled with these factors before balancing.', NULL, 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000015', 'Contour-area (contour-volume) method', 'A volume method that measures the horizontal area enclosed by each contour line and integrates those areas vertically using the contour interval, applying the average-end-area or prismoidal formula. Ideal for reservoirs, ponds, and stockpiles.', NULL, 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000016', 'Contour interval', 'The constant vertical distance between successive contour lines on a topographic map. In contour-volume work it plays the role that the station distance plays in the cross-section method.', NULL, 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000017', 'Stage–storage (elevation–capacity) curve', 'A curve giving the cumulative stored volume of a reservoir below each pool elevation. It is built by summing contour-layer volumes from the lowest contour upward.', NULL, 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000018', 'Earthwork tabulation', 'A station-by-station table that converts cross-section end areas into segment volumes (by average-end-area or prismoidal formula) and accumulates separate running totals of cut and fill, reported in cubic yards.', NULL, 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000019', 'Balance point', 'A station along an alignment where cumulative cut equals cumulative fill, so the earth needed up to that point is supplied entirely from on-site excavation without borrow or waste.', NULL, 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000020', 'Mass-haul diagram', 'A plot of cumulative net earthwork volume against station. Its shape shows haul distances and directions and identifies balance points, guiding the most economical movement of earth.', NULL, 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO flashcards (id, term, definition, hint_1, module_id, lesson_id, category, tags, is_published, review_status, difficulty_level) VALUES ('eeee0940-0000-0000-0000-000000000021', 'Borrow and waste', 'Borrow is material imported to a project when fill exceeds available cut; waste is excavated material hauled off when cut exceeds fill. Both are determined after applying shrinkage and swell factors.', NULL, 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', 'surveying', ARRAY['buildout','module-9']::text[], true, 'approved', 'intermediate');
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000001', 'The coordinate (shoelace) method and the Double Meridian Distance (DMD) method, applied to the same closed traverse, will generally produce:', 'multiple_choice', '["Different areas, because DMD uses latitudes and departures","The identical area, because they integrate the same closed figure","Areas that differ by exactly a factor of two","An area only if the traverse is a rectangle"]'::jsonb, 'The identical area, because they integrate the same closed figure', 'The two methods are algebraically equivalent; they merely organize the same computation differently. Both compute twice the area of the closed polygon, so after halving they give the identical result.', 'easy', 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000002', 'In the DMD method, the Double Meridian Distance of the FIRST course equals:', 'multiple_choice', '["Its own latitude","Its own departure","Twice its length","Zero, always"]'::jsonb, 'Its own departure', 'By rule, the DMD of the first course equals its own departure; each subsequent DMD adds the previous departure and the current departure; the last course''s DMD again equals its own departure, providing a check.', 'medium', 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000003', 'A parcel computes to 130,680 square feet. What is its area in acres?', 'numeric_input', '[]'::jsonb, '3', 'Divide square feet by 43,560: 130,680 ÷ 43,560 = 3.00 acres.', 'easy', 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000004', 'You should compute parcel area before adjusting (balancing) the traverse, so the closure error is included in the area.', 'true_false', '["True","False"]'::jsonb, 'False', 'Adjust the traverse FIRST. Computing area on an unadjusted traverse bakes the linear misclosure into the parcel size, distorting the reported area.', 'medium', 'c1000009-0000-0000-0000-000000000009', '429a1bdd-bc34-4723-bb7d-daf1db4d2665', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000005', 'Which formula gives the area of a triangle when only the three side lengths are known?', 'multiple_choice', '["A = ½·base·height","A = ½·a·b·sin C","Heron''s formula, A = √[s(s−a)(s−b)(s−c)]","The shoelace formula"]'::jsonb, 'Heron''s formula, A = √[s(s−a)(s−b)(s−c)]', 'Heron''s formula needs only the three sides (via the semiperimeter s). The ½·a·b·sin C form requires the included angle, and ½·base·height requires a measured height.', 'easy', 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000006', 'Simpson''s one-third rule for area-by-offsets requires that:', 'multiple_choice', '["The offsets be unequal but increasing","There be an even number of equal intervals (an odd number of offsets)","There be exactly two offsets","The base line follow the curved boundary exactly"]'::jsonb, 'There be an even number of equal intervals (an odd number of offsets)', 'Simpson''s 1/3 rule pairs intervals into parabolic segments, so it needs an even number of equal intervals (hence an odd number of offsets). The trapezoidal rule has no such restriction.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000007', 'A triangle has sides a = 60 ft and b = 80 ft with an included angle C = 30°. Using A = ½·a·b·sin C, what is its area in square feet?', 'numeric_input', '[]'::jsonb, '1200', 'A = ½ × 60 × 80 × sin 30° = ½ × 4800 × 0.5 = 1200 square feet.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000008', 'Under Simpson''s one-third rule, the interior offsets at ODD positions (h1, h3, …) receive which weight?', 'multiple_choice', '["1","2","4","0.5"]'::jsonb, '4', 'Simpson''s weighting is: end offsets ×1, odd-position interior offsets ×4, even-position interior offsets ×2, all multiplied by d/3.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'a9daa1c2-b0ae-40ab-ac31-c0295afe69b0', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000009', 'A rectangular field is 600 ft wide. To cut off 4.00 acres (174,240 sq ft) with a line parallel to the north boundary, at what depth (ft) south of that boundary should the dividing line be set?', 'numeric_input', '[]'::jsonb, '290.4', 'For a parallel cut on a rectangle, d = A_target / width = 174,240 ÷ 600 = 290.4 ft.', 'medium', 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000010', 'Land partitioning is best described as:', 'multiple_choice', '["Computing the area of a parcel from its coordinates","The inverse problem: locating a line that cuts off a specified target area","Converting square feet to acres","Adjusting a traverse for closure"]'::jsonb, 'The inverse problem: locating a line that cuts off a specified target area', 'Partitioning inverts the area computation: given a required area, you solve for the dividing line that severs exactly that area, then describe each resulting parcel.', 'easy', 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000011', 'In Texas, dividing a tract into lots for sale typically triggers platting and plat-approval requirements under the Local Government Code, and the surveyor must avoid creating landlocked parcels.', 'true_false', '["True","False"]'::jsonb, 'True', 'Subdividing land for sale generally invokes Texas Local Government Code Ch. 212 (municipal) or Ch. 232 (county) platting rules, and many counties prohibit conveyances that create landlocked tracts without access.', 'medium', 'c1000009-0000-0000-0000-000000000009', '704310c8-fb7a-49e1-8912-62f081890afa', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000012', 'Two cross-sections have end areas A1 = 90 sq ft and A2 = 150 sq ft and are 100 ft apart. By the average-end-area method, the volume between them is:', 'multiple_choice', '["12,000 cubic feet","24,000 cubic feet","6,000 cubic feet","240 cubic feet"]'::jsonb, '12,000 cubic feet', 'V = L·(A1+A2)/2 = 100 × (90+150)/2 = 100 × 120 = 12,000 cubic feet.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000013', 'In the prismoidal formula V = (L/6)(A1 + 4·Am + A2), the middle area Am is:', 'multiple_choice', '["The simple average of A1 and A2","The area of the mid-section, whose dimensions are the averages of the two ends","Always zero","Twice the larger end area"]'::jsonb, 'The area of the mid-section, whose dimensions are the averages of the two ends', 'Am is the area computed from a section whose linear dimensions are the averages of the end sections. It is NOT the average of the two end areas — confusing the two is a common error.', 'hard', 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000014', 'Convert 54,000 cubic feet of excavation to cubic yards.', 'numeric_input', '[]'::jsonb, '2000', '1 cubic yard = 27 cubic feet, so 54,000 ÷ 27 = 2,000 cubic yards.', 'easy', 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000015', 'Cut and fill volumes can simply be netted against each other without any adjustment, because a cubic yard of cut always becomes a cubic yard of fill.', 'true_false', '["True","False"]'::jsonb, 'False', 'Soil swells when excavated and shrinks when compacted into fill, so cut and fill are tracked separately and reconciled with shrinkage/swell factors before balancing.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'de47d43a-6820-4784-96d0-40a3cfaa4621', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000016', 'In the contour-area method of computing volume, the role played by the station distance in the cross-section method is taken by the:', 'multiple_choice', '["Map scale","Contour interval (vertical spacing between contours)","Length of the longest contour","Number of contours"]'::jsonb, 'Contour interval (vertical spacing between contours)', 'Contour areas are treated as successive ''end areas'' separated vertically by the contour interval, which is the ''length'' in the average-end-area or prismoidal formula.', 'medium', 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000017', 'Two contours 2 ft apart enclose areas of 5,000 sq ft (lower) and 7,000 sq ft (upper). The volume of the layer between them, by average-end-area, is how many cubic feet?', 'numeric_input', '[]'::jsonb, '12000', 'V = h·(A_lower + A_upper)/2 = 2 × (5,000 + 7,000)/2 = 2 × 6,000 = 12,000 cubic feet.', 'medium', 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000018', 'The contour-area method is especially well suited to which task?', 'multiple_choice', '["Computing the area of a small rectangular lot","Building a reservoir stage–storage (elevation–capacity) curve","Balancing a closed traverse","Converting bearings to azimuths"]'::jsonb, 'Building a reservoir stage–storage (elevation–capacity) curve', 'Summing contour-layer volumes from the lowest contour upward gives cumulative storage at each pool elevation — exactly the stage–storage curve used in reservoir and pond design.', 'easy', 'c1000009-0000-0000-0000-000000000009', '133e303e-b95a-45de-8d33-b39ce8eb2d40', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000019', 'A balance point on an earthwork alignment is a station where:', 'multiple_choice', '["The cut area equals the fill area in a single cross-section","Cumulative cut volume equals cumulative fill volume","The mass-haul diagram reaches its maximum","The contour interval changes"]'::jsonb, 'Cumulative cut volume equals cumulative fill volume', 'A balance point is where the running totals of cut and fill are equal, so material up to that station is supplied entirely on site. On the mass-haul diagram it is where the cumulative-volume curve returns to the baseline.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000020', 'Between two stations 100 ft apart, the cut end areas are 81 sq ft and 81 sq ft. What is the cut volume for that segment in cubic yards?', 'numeric_input', '[]'::jsonb, '300', 'Average-end-area volume = 100 × (81+81)/2 = 100 × 81 = 8,100 cubic feet; ÷27 = 300 cubic yards.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('eeee0930-0000-0000-0000-000000000021', 'Define the difference between shrinkage and swell in earthwork.', 'short_answer', '[]'::jsonb, 'Swell is the volume increase of excavated material when loosened (relevant to hauling); shrinkage is the volume decrease of material compacted into fill relative to its in-place borrow volume.', 'Excavated soil swells (occupies more space loose), while soil compacted into an embankment shrinks relative to its borrow-pit volume. Both factors are applied before balancing cut against fill.', 'medium', 'c1000009-0000-0000-0000-000000000009', 'df466917-ac9e-4799-a168-8475631ca487', ARRAY['buildout','module-9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0960-0000-0000-0000-000000000001', 'A closed four-sided parcel has corner coordinates (X, Y), in feet, of A(0, 0), B({{xb}}, 0), C({{xb}}, {{yc}}), and D(0, {{yd}}), taken counter-clockwise. Using the coordinate (shoelace) method, what is the parcel area in ACRES? (1 acre = 43,560 sq ft.)', 'numeric_input', '[]'::jsonb, '0', 'The shoelace method yields a double area of {{xb}}·{{yc}} + {{xb}}·{{yd}}; halving gives {{areaSqFt:f1}} sq ft, which is {{areaSqFt:f1}} ÷ 43,560 = {{_answer}} acres.', 'medium', 'c1000009-0000-0000-0000-000000000009', NULL, ARRAY['buildout','module-9','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0950-0000-0000-0000-000000000001', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0960-0000-0000-0000-000000000002', 'A strip of land between a straight base line and an irregular boundary is {{length}} ft long. The perpendicular offset to the boundary is {{o1}} ft at one end and {{o2}} ft at the other end. Approximating the strip as a trapezoid, what is its area in square feet (average of the two end offsets × length)?', 'numeric_input', '[]'::jsonb, '0', 'Treating the strip as a trapezoid, area = average offset × length = (({{o1}}+{{o2}})/2) × {{length}} = {{_answer}} sq ft.', 'easy', 'c1000009-0000-0000-0000-000000000009', NULL, ARRAY['buildout','module-9','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0950-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0960-0000-0000-0000-000000000003', 'Two cross-sections {{length}} ft apart have cut end areas of {{a1}} sq ft and {{a2}} sq ft. Using the average-end-area method, V = L·(A1+A2)/2, what is the cut volume between the sections in CUBIC YARDS? (1 cu yd = 27 cu ft.)', 'numeric_input', '[]'::jsonb, '0', 'Average-end-area volume = {{length}} × (({{a1}}+{{a2}})/2) = {{volCuFt:f1}} cubic feet; dividing by 27 gives {{_answer}} cubic yards.', 'medium', 'c1000009-0000-0000-0000-000000000009', NULL, ARRAY['buildout','module-9','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0950-0000-0000-0000-000000000003', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, tags, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, lesson_id, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('eeee0960-0000-0000-0000-000000000004', 'Perpendicular offsets to an irregular boundary are taken at a common interval of {{d}} ft. Five offsets are recorded: end offsets {{h0}} ft and {{h4}} ft, and interior offsets {{h1}} ft, {{h2}} ft, and {{h3}} ft. Using the trapezoidal rule, A = d·[(h0+hn)/2 + (interior offsets)], what is the area in square feet?', 'numeric_input', '[]'::jsonb, '0', 'Trapezoidal rule: A = d·[(h0+hn)/2 + Σ interior] = {{d}} × (({{h0}}+{{h4}})/2 + {{h1}}+{{h2}}+{{h3}}) = {{_answer}} sq ft.', 'medium', 'c1000009-0000-0000-0000-000000000009', NULL, ARRAY['buildout','module-9','dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'eeee0950-0000-0000-0000-000000000004', 0.5);
